const input = $json;
const allLinks = input.links || [];

// Get company_website from upstream
let companyWebsite = '';
try { companyWebsite = $('Extract Full Description').item.json.company_website || ''; } catch(e) {}
if (!companyWebsite && allLinks.length > 0) {
  // Derive from first link
  const first = allLinks[0];
  companyWebsite = first.split('/').slice(0, 3).join('/');
}
const baseUrl = companyWebsite.replace(/\/$/, '');

// Priority patterns for company research
const priorityPatterns = [/\/about/i, /\/team/i, /\/product/i, /\/service/i, /\/what-we-do/i, /\/our-story/i, /\/solution/i, /\/client/i, /\/customer/i, /\/market/i, /\/impact/i, /\/specialisation/i, /\/capabilities/i, /\/technology/i, /\/platform/i, /\/values/i, /\/culture/i, /\/innovation/i];

// Exclude patterns (low-value for company research)
const excludePatterns = [/\/blog/i, /\/news/i, /\/press/i, /\/job-/i, /\/job_/i, /\/careers\//i, /\/tv/i, /\/video/i, /\/podcast/i, /\/webinar/i, /\/event/i, /\/faq/i, /\/support/i, /\/help/i, /\/login/i, /\/signup/i, /\/privacy/i, /\/terms/i, /\/cookie/i, /\/test\//i, /\/404/i, /improve-your-resume/i, /counter-offer/i, /interview-question/i, /how-to-/i, /how-do-i-/i];

const urls = [];
if (baseUrl) urls.push(baseUrl);

// First pass: priority pages only
for (const link of allLinks) {
  if (urls.length >= 10) break;
  if (!link || link === baseUrl || link === baseUrl + '/') continue;
  const isExcluded = excludePatterns.some(p => p.test(link));
  if (isExcluded) continue;
  const isPriority = priorityPatterns.some(p => p.test(link));
  if (isPriority && !urls.includes(link) && !link.endsWith('.pdf')) {
    urls.push(link);
  }
}

// Second pass: fill remaining with non-excluded top-level pages
if (urls.length < 10) {
  for (const link of allLinks) {
    if (urls.length >= 10) break;
    if (!link || urls.includes(link) || link.endsWith('.pdf')) continue;
    const isExcluded = excludePatterns.some(p => p.test(link));
    if (isExcluded) continue;
    // Prefer shallow pages (fewer path segments)
    const depth = (link.replace(baseUrl, '').match(/\//g) || []).length;
    if (depth <= 2) urls.push(link);
  }
}

// Filter out any empty URLs
const finalUrls = urls.filter(u => u && u.startsWith('http'));

return finalUrls.map(url => ({ json: {
  url,
  scrape_urls_count: finalUrls.length,
  map_urls_found: input.map_urls_found || 0,
  sitemap_source: input.sitemap_source || 'none',
  sitemap_urls_found: input.sitemap_urls_found || 0,
  total_discovered: input.total_discovered || 0
} }));

const input = $json;
const urls = input.scrape_urls || [];
const apiKey = 'fc-2357a08dfb754e50a94dfe4c1d15d2ca';
let combinedMarkdown = '';

for (const url of urls) {
  try {
    const resp = await fetch('https://api.firecrawl.dev/v1/scrape', {
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ url, formats: ['markdown'], onlyMainContent: true })
    });
    const data = await resp.json();
    const md = data.data?.markdown || '';
    if (md) {
      combinedMarkdown += '\n\n--- PAGE: ' + url + ' ---\n\n' + md.slice(0, 3000);
    }
  } catch (e) {}
}

return [{ json: {
  ...input,
  data: { markdown: combinedMarkdown.slice(0, 12000) }
} }];

const job = $('Prepare Job Scrape').item.json;
const scrapeResult = $('Firecrawl Scrape Job Page').item.json;
const fullDescription = scrapeResult.data?.markdown || job.description || '';

// Prioritize company_website from Google Sheet if already set
let companyWebsite = (job.company_website || '').trim();

if (!companyWebsite.includes('http')) {
  const excludedDomains = [
    'seek.com', 'seek.com.au', 'au.seek.com',
    'linkedin.com', 'indeed.com', 'glassdoor.com',
    'jora.com', 'adzuna.com', 'careerone.com',
    'ethicaljobs.com.au', 'google.com', 'googleapis.com',
    'gstatic.com', 'facebook.com', 'twitter.com', 'x.com',
    'cdn.seeklearning.com.au', 'help.au.seek.com',
    'box.com', 'app.box.com', 'dropbox.com', 'drive.google.com',
    'sharepoint.com', 'onedrive.live.com', 'wetransfer.com',
    'iworkfor.nsw.gov.au', 'jobs.nsw.gov.au', 'mycareer.nsw.gov.au',
    'youtube.com', 'vimeo.com', 'wikipedia.org', 'reddit.com'
  ];
  const urlRegex = /https?:\/\/(?:www\.)?([a-zA-Z0-9.-]+\.[a-z]{2,})/gi;
  let match;
  while ((match = urlRegex.exec(fullDescription)) !== null) {
    const domain = match[1].toLowerCase();
    const isExcluded = excludedDomains.some(ex => domain === ex || domain.endsWith('.' + ex));
    if (!isExcluded) {
      companyWebsite = match[0].split(/[)\s]/)[0];
      break;
    }
  }
}

return [{ json: {
  ...job,
  description: fullDescription.slice(0, 10000),
  company_website: companyWebsite,
  status: 'enrichment_pending'
} }];

const job = $('Extract Full Description').item.json;
const companyMarkdown = $json.data?.markdown || 'No website content available';

function clean(str) {
  return (str || '').replace(/[\x00-\x1f\x7f]/g, ' ').replace(/\s+/g, ' ').trim();
}

const body = {
  messages: [
    {
      role: "system",
      content: "You extract concise company research for job application tailoring. Return JSON only with: company_summary (2-3 sentences), products (array), customers (array), values (array), technical_signals (array of tech/tools mentioned), hiring_signals (array), keywords (array of important terms for resume tailoring)."
    },
    {
      role: "user",
      content: "Company: " + clean(job.company_name) + " Job Title: " + clean(job.title) + " Company Website Content: " + clean(companyMarkdown).slice(0, 4000) + " Job Description: " + clean(job.description).slice(0, 3000)
    }
  ],
  response_format: { type: "json_object" },
  max_tokens: 1000
};

return [{ json: { body_string: JSON.stringify(body) } }];

// Get full data from the enrichment pipeline
const job = $('Extract Full Description').item.json;
const raw = $json.choices?.[0]?.message?.content || '{}';
let company;
try { company = JSON.parse(raw); } catch (e) { company = { parse_error: true, raw: raw.slice(0, 500) }; }

const pdfUrl = job.job_pdf_url || '';

let scrapeInput = {};
try { scrapeInput = $('Scrape and Combine Pages').item.json || {}; } catch(e) {}

company.scraped_urls = scrapeInput.scrape_urls || [];
company.discovery = {
  sitemap_source: scrapeInput.sitemap_source || 'none',
  sitemap_urls_found: scrapeInput.sitemap_urls_found || 0,
