  total_discovered: scrapeInput.total_discovered || 0,
  pages_scraped: (scrapeInput.scrape_urls || []).length
};

const companyResearchStr = JSON.stringify(company);

// Pass full data for vector embedding (before trimming for sheet)
return [{ json: {
  job_id: job.job_id,
  job_url_hash: job.job_url_hash,
  title: job.title,
  company_name: job.company_name,
  company_url: job.company_url || '',
  company_website: job.company_website || '',
  location: job.location || '',
  remote_policy: job.remote_policy || '',
  salary: job.salary || '',
  contract_type: job.contract_type || '',
  search_keywords: job.search_keywords || '',
  job_url: job.job_url || '',
  full_description: (job.description || '').slice(0, 10000),
  company_summary: company.company_summary || 'No summary available',
  company_research_str: companyResearchStr,
  job_pdf_url: pdfUrl,
  status: 'enriched',
  updated_at: new Date().toISOString()
} }];

const driveFile = $json;
const pdfUrl = driveFile.webViewLink || driveFile.webContentLink || '';
const hyperlink = pdfUrl ? '=HYPERLINK("' + pdfUrl + '","View Screenshot")' : '';
return [{ json: { job_pdf_url: hyperlink } }];

const input = $json;
const screenshotUrl = input.data?.screenshot || '';

// Get job data from upstream
let job = {};
try { job = $('Prepare Job Scrape').item.json; } catch(e) {}

const now = new Date();
const day = String(now.getDate()).padStart(2, '0');
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const mon = months[now.getMonth()];
const yr = String(now.getFullYear()).slice(-2);
const dateStr = `${day}_${mon}_${yr}`;

const company = (job.company_name || 'Company').replace(/[^a-zA-Z0-9]/g, '_');
const title = (job.title || 'Job').replace(/[^a-zA-Z0-9]/g, '_').slice(0, 40);
const location = (job.location || 'Sydney').replace(/[^a-zA-Z0-9]/g, '_').slice(0, 30);
const fileName = `Ashok_Mulchandani_${dateStr}_JD_screenshot_${company}_${title}_${location}.png`;

return [{ json: { file_name: fileName, screenshot_url: screenshotUrl } }];

const job = $('Extract Full Description').item.json;
const googleMarkdown = $json.data?.markdown || '';

const excludedDomains = [
  'seek.com', 'seek.com.au', 'au.seek.com',
  'linkedin.com', 'indeed.com', 'glassdoor.com',
  'jora.com', 'adzuna.com', 'careerone.com',
  'ethicaljobs.com.au', 'google.com', 'googleapis.com',
  'gstatic.com', 'facebook.com', 'twitter.com', 'x.com',
  'youtube.com', 'wikipedia.org', 'reddit.com',
  'duckduckgo.com', 'external-content.duckduckgo.com', 'bing.com',
  'cdn.seeklearning.com.au', 'help.au.seek.com',
  'apps.apple.com', 'play.google.com', 'itunes.apple.com',
  'findglocal.com', 'start.duckduckgo.com', 'duck.ai',
  'insideduckduckgo.substack.com'
];

const urlRegex = /https?:\/\/(?:www\.)?([a-zA-Z0-9.-]+\.[a-z]{2,})/gi;
let match;
let companyWebsite = '';
while ((match = urlRegex.exec(googleMarkdown)) !== null) {
  const domain = match[1].toLowerCase();
  const isExcluded = excludedDomains.some(ex => domain === ex || domain.endsWith('.' + ex));
  if (!isExcluded) {
    companyWebsite = 'https://' + domain;
    break;
  }
}

return [{ json: {
  ...job,
  company_website: companyWebsite
} }];

const items = $('Read Discovered Jobs').all();
const discovered = items.filter(i => (i.json.status || '').trim().toLowerCase() === 'discovered');
if (discovered.length === 0) throw new Error('No discovered jobs found');
return discovered.slice(0, 5).map(i => ({ json: i.json }));

// Get full data from previous node (Parse Company Summary)
const job = $json;

let companyResearchStr = job.company_research_str || '{}';

const parts = [
  'Job Title: ' + (job.title || ''),
  'Company: ' + (job.company_name || ''),
  'Location: ' + (job.location || ''),
  'Description: ' + (job.full_description || '').slice(0, 5000),
];

let researchObj = {};
try { researchObj = JSON.parse(companyResearchStr); } catch(e) {}
parts.push('Company Summary: ' + (researchObj.company_summary || job.company_summary || ''));
parts.push('Products: ' + (researchObj.products || []).join(', '));
parts.push('Customers: ' + (researchObj.customers || []).join(', '));
parts.push('Values: ' + (researchObj.values || []).join(', '));
parts.push('Technical Signals: ' + (researchObj.technical_signals || []).join(', '));
parts.push('Hiring Signals: ' + (researchObj.hiring_signals || []).join(', '));
parts.push('Keywords: ' + (researchObj.keywords || []).join(', '));

const content = parts.filter(Boolean).join('\n');

const text = content.toLowerCase();
let industry = 'General';
if (text.includes('retail') || text.includes('e-commerce')) industry = 'Retail';
else if (text.includes('defence') || text.includes('navy')) industry = 'Defence';
else if (text.includes('health') || text.includes('medical')) industry = 'Healthcare';
else if (text.includes('manufacturing') || text.includes('factory')) industry = 'Manufacturing';
else if (text.includes('finance') || text.includes('banking') || text.includes('fintech')) industry = 'Finance';
else if (text.includes('government') || text.includes('council')) industry = 'Government';
else if (text.includes('logistics') || text.includes('supply chain')) industry = 'Supply Chain';

let companyResearchObj = {};
try { companyResearchObj = JSON.parse(companyResearchStr); } catch(e) {}

const metadata = {
  search_keywords: job.search_keywords || '',
  job_url: job.job_url || '',
  company_website: job.company_website || '',
  contract_type: job.contract_type || '',
  remote_policy: job.remote_policy || '',
  salary: job.salary || '',
  company_research: companyResearchObj,
  description: (job.full_description || '').slice(0, 10000),
  enriched_at: new Date().toISOString()
};

return [{ json: {
  ...job,
  industry: industry,
  fit_score: null,
    content: content.slice(0, 8000).replace(/\\/g, ' ').replace(/"/g, "'").replace(/[\x00-\x1f\x7f]/g, ' '),
  metadata: metadata,
  sheet_data: { job_id: job.job_id, job_url_hash: job.job_url_hash, title: job.title, company_name: job.company_name, company_url: job.company_url || '', company_website: job.company_website || '', location: job.location || '', remote_policy: job.remote_policy || '', salary: job.salary || '', contract_type: job.contract_type || '', description: 'See Supabase', company_summary: job.company_summary || '', company_research: 'Full data in Supabase', job_pdf_url: job.job_pdf_url || '', status: 'enriched', updated_at: new Date().toISOString() }
} }];

// Use sheet_data from the item that flowed through the chain
// Upsert to Supabase returns {}, but we can access Prepare Vector Data via expression
let job;
try { job = $('Prepare Vector Data').item.json; } catch(e) { job = $json; }
const sd = job.sheet_data || job;
return [{ json: sd }];

const items = $input.all();
let combinedMarkdown = '';

for (const item of items) {
  const md = item.json.data?.markdown || '';
  const url = item.json.data?.metadata?.sourceURL || '';
  if (md) {
    combinedMarkdown += '\n\n--- PAGE: ' + url + ' ---\n\n' + md.slice(0, 2000);
  }
}

return [{ json: {
  data: { markdown: combinedMarkdown.slice(0, 20000) },
  scrape_urls_count: items.length,
  map_urls_found: items[0]?.json.map_urls_found || 0
} }];

const mapResult = $('Firecrawl Scrape Company').item.json;
const mapLinks = mapResult.links || [];
const sitemapXml = $json.data || $json || '';

// Extract <loc> URLs from sitemap XML
let sitemapUrls = [];
if (typeof sitemapXml === 'string' && sitemapXml.includes('<loc>')) {
  const re = /<loc>(https?:\/\/[^<]+)<\/loc>/gi;
  let m;
  while ((m = re.exec(sitemapXml)) !== null) sitemapUrls.push(m[1]);
}

// Combine and dedupe
const allLinks = [...new Set([...sitemapUrls, ...mapLinks])];

return [{ json: { links: allLinks, sitemap_urls_found: sitemapUrls.length, map_urls_found: mapLinks.length } }];

const robotsTxt = $json.data || '';
const mapResult = $('Firecrawl Scrape Company').item.json;
const mapLinks = mapResult.links || [];

let companyWebsite = '';
try { companyWebsite = $('Extract Full Description').item.json.company_website || ''; } catch(e) {}
const baseUrl = companyWebsite.replace(/\/$/, '');

// Try both www and non-www for sitemap
const baseUrls = [baseUrl];
if (baseUrl.includes('://www.')) {
  baseUrls.push(baseUrl.replace('://www.', '://'));
} else {
  baseUrls.push(baseUrl.replace('://', '://www.'));
}

// Extract sitemap URL from robots.txt
let sitemapUrl = '';
if (typeof robotsTxt === 'string') {
  const sm = robotsTxt.match(/Sitemap:\s*(https?:\/\/[^\s]+)/i);
  if (sm) sitemapUrl = sm[1].trim();
}

// If no sitemap in robots.txt, try common paths
const sitemapUrls = [];
if (sitemapUrl) {
  sitemapUrls.push(sitemapUrl);
} else {
  for (const bu of baseUrls) {
    sitemapUrls.push(bu + '/sitemap.xml');
    sitemapUrls.push(bu + '/sitemap_index.xml');
  }
}

return [{ json: {
  sitemap_url: sitemapUrls[0] || baseUrl + '/sitemap.xml',
  all_sitemap_urls: sitemapUrls,
  map_links: mapLinks,
  base_url: baseUrl
} }];

const sitemapXml = $json.data || $json.body || '';
const prevData = $('Parse Robots Sitemap').item.json;
const mapLinks = prevData.map_links || [];
const baseUrl = prevData.base_url || '';

// Extract <loc> URLs from sitemap XML
let sitemapUrls = [];
if (typeof sitemapXml === 'string' && sitemapXml.includes('<loc>')) {
  const re = /<loc>(https?:\/\/[^<]+)<\/loc>/gi;
  let m;
  while ((m = re.exec(sitemapXml)) !== null) {
    const url = m[1];
    if (!url.endsWith('.pdf') && !url.includes('/404')) {
      sitemapUrls.push(url);
    }
  }
}

// Combine and dedupe sitemap + map URLs
const allLinks = [...new Set([...sitemapUrls, ...mapLinks])];

return [{ json: {
  links: allLinks,
  sitemap_source: sitemapUrls.length > 0 ? prevData.sitemap_url : 'none',
  sitemap_urls_found: sitemapUrls.length,
  map_urls_found: mapLinks.length,
  total_discovered: allLinks.length
} }];
